import{_ as a,c as s,o as r,b as t}from"./app.56f378f3.js";const k='{"title":"\u041F\u0430\u043D\u0447\u0430\u0431\u0440\u0430\u0445\u043C\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430","description":"","frontmatter":{"title":"\u041F\u0430\u043D\u0447\u0430\u0431\u0440\u0430\u0445\u043C\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430","subtitle":"\u041E\u0434\u043D\u0430 \u0438\u0437 13 \u0428\u0430\u0439\u0432\u0430 \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434 \u0438 \u043E\u0434\u043D\u0430 \u0438\u0437 32 \u0423\u043F\u0430\u043D\u0438\u0448\u0430\u0434 \u041A\u0440\u0438\u0448\u043D\u0430 \u042F\u0434\u0436\u0443\u0440\u0432\u0435\u0434\u044B \u043E \u043F\u044F\u0442\u0438\u043B\u0438\u043A\u043E\u043C \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0435","sans":"\u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u094B\u092A\u0928\u093F\u0937\u0924\u094D","trans":"pa\xF1cabrahmopani\u1E63at","tags":"text","date":"2021-02-02T00:00:00.000Z"},"headers":[],"relativePath":"texts/panchabrahma/index.md"}',p={},i=t('<div class="stanza"><p class="sans">\u0950 \u0965<br> \u0938\u0939 \u0928\u093E\u0935\u0935\u0924\u0941 \u0938\u0939 \u0928\u094C \u092D\u0941\u0928\u0915\u094D\u0924\u0941 \u0938\u0939 \u0935\u0940\u0930\u094D\u092F\u0902 \u0915\u0930\u0935\u093E\u0935\u0939\u0948 \u0964<br> \u0924\u0947\u091C\u0938\u094D\u0935\u093F\u0928\u093E\u0935\u0927\u0940\u0924\u092E\u0938\u094D\u0924\u0941 \u092E\u093E \u0935\u093F\u0926\u094D\u0935\u093F\u0937\u093E\u0935\u0939\u0948 \u0965<br> \u0950 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0936\u093E\u0928\u094D\u0924\u093F\u0903 \u0965</p><p class="trans">o\u1E41 \u0965<br> saha n\u0101vavatu saha nau bhunaktu saha v\u012Brya\u1E41 karav\u0101vahai \u0964<br> tejasvin\u0101vadh\u012Btamastu m\u0101 vidvi\u1E63\u0101vahai \u0965<br> o\u1E41 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u015B\u0101nti\u1E25 \u0965 hari\u1E25 o\u1E41 \u0965</p><p>\u0414\u0430 \u0437\u0430\u0449\u0438\u0442\u0438\u0442 \u041E\u043D \u043D\u0430\u0441 \u043E\u0431\u043E\u0438\u0445 (\u0443\u0447\u0438\u0442\u0435\u043B\u044F \u0438 \u043E\u0431\u0443\u0447\u0430\u0435\u043C\u043E\u0433\u043E), \u0432\u043C\u0435\u0441\u0442\u0435, (\u043E\u0442\u043A\u0440\u044B\u0432 \u0437\u043D\u0430\u043D\u0438\u0435). \u0414\u043E \u0437\u0430\u0449\u0438\u0442\u0438\u0442 \u041E\u043D \u043D\u0430\u0441 \u043E\u0431\u043E\u0438\u0445, (\u043E\u0434\u0430\u0440\u0438\u0432 \u043F\u043B\u043E\u0434\u0430\u043C\u0438 \u0437\u043D\u0430\u043D\u0438\u044F). \u041F\u0443\u0441\u0442\u044C \u043C\u044B \u0432\u043C\u0435\u0441\u0442\u0435 \u0434\u043E\u0441\u0442\u0438\u0433\u043D\u0435\u043C \u0441\u0438\u043B\u044B. \u041F\u0443\u0441\u0442\u044C \u0438\u0437\u0443\u0447\u0430\u0435\u043C\u043E\u0435 \u043D\u0430\u043C\u0438 \u0431\u0443\u0434\u0435\u0442 \u0432\u043E\u043E\u0434\u0443\u0448\u0435\u0432\u043B\u044F\u044E\u0449\u0438\u043C. \u041F\u0443\u0441\u0442\u044C \u043C\u044B \u043D\u0435 \u0431\u0443\u0434\u0435\u043C \u0438\u0441\u043A\u0430\u0442\u044C \u043D\u0435\u0434\u043E\u0441\u0442\u0430\u0442\u043A\u0438 \u0434\u0440\u0443\u0433 \u0432 \u0434\u0440\u0443\u0433\u0435. \u041E\u043C! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439! \u041F\u043E\u043A\u043E\u0439!</p></div><div class="stanza"><a href="#s1" id="s1" class="num">1</a><p class="sans">\u0905\u0925 \u092A\u0948\u092A\u094D\u092A\u0932\u093E\u0926\u094B \u092D\u0917\u0935\u093E\u0928\u094D\u092D\u094B \u0915\u093F\u092E\u093E\u0926\u094C \u0915\u093F\u0902 \u091C\u093E\u0924\u092E\u093F\u0924\u093F \u0964<br> \u0938\u0926\u094D\u092F\u094B \u091C\u093E\u0924\u092E\u093F\u0924\u093F \u0964<br> \u0915\u093F\u0902 \u092D\u0917\u0935 \u0907\u0924\u093F \u0964<br> \u0905\u0918\u094B\u0930 \u0907\u0924\u093F \u0964<br> \u0915\u093F\u0902 \u092D\u0917\u0935 \u0907\u0924\u093F \u0964<br> \u0935\u093E\u092E\u0926\u0947\u0935 \u0907\u0924\u093F \u0964<br> \u0915\u093F\u0902 \u0935\u093E \u092A\u0941\u0928\u0930\u093F\u092E\u0947 \u092D\u0917\u0935 \u0907\u0924\u093F \u0964<br> \u0924\u0924\u094D\u092A\u0941\u0930\u0941\u0937 \u0907\u0924\u093F \u0964<br> \u0915\u093F\u0902 \u0935\u093E \u092A\u0941\u0928\u0930\u093F\u092E\u0947 \u092D\u0917\u0935 \u0907\u0924\u093F \u0964<br> \u0938\u0930\u094D\u0935\u0947\u0937\u093E\u0902 \u0926\u093F\u0935\u094D\u092F\u093E\u0928\u093E\u0902 \u092A\u094D\u0930\u0947\u0930\u092F\u093F\u0924\u093E \u0908\u0936\u093E\u0928 \u0907\u0924\u093F \u0964<br> \u0908\u0936\u093E\u0928\u094B \u092D\u0942\u0924\u092D\u0935\u094D\u092F\u0938\u094D\u092F \u0938\u0930\u094D\u0935\u0947\u0937\u093E\u0902 \u0926\u0947\u0935\u092F\u094B\u0917\u093F\u0928\u093E\u092E\u094D \u0964<br> \u0915\u0924\u093F \u0935\u0930\u094D\u0923\u093E\u0903 \u0964<br> \u0915\u0924\u093F \u092D\u0947\u0926\u093E\u0903 \u0964<br> \u0915\u0924\u093F \u0936\u0915\u094D\u0924\u092F\u0903 \u0964<br> \u092F\u0924\u094D\u0938\u0930\u094D\u0935\u0902 \u0924\u0926\u094D\u0917\u0941\u0939\u094D\u092F\u092E\u094D \u0964<br> \u0924\u0938\u094D\u092E\u0948 \u0928\u092E\u094B \u092E\u0939\u093E\u0926\u0947\u0935\u093E\u092F \u092E\u0939\u093E\u0930\u0941\u0926\u094D\u0930\u093E\u092F \u092A\u094D\u0930\u094B\u0935\u093E\u091A \u0924\u0938\u094D\u092E\u0948 \u092D\u0917\u0935\u093E\u0928\u094D\u092E\u0939\u0947\u0936\u0903 \u0964<br> \u0917\u094B\u092A\u094D\u092F\u093E\u0926\u094D\u0917\u094B\u092A\u094D\u092F\u0924\u0930\u0902 \u0932\u094B\u0915\u0947 \u092F\u0926\u094D\u092F\u0938\u094D\u0924\u093F \u0936\u094D\u0930\u0941\u0923\u0941 \u0936\u093E\u0915\u0932 \u0964<br> \u0938\u0926\u094D\u092F\u094B \u091C\u093E\u0924\u0902 \u092E\u0939\u0940 \u092A\u0942\u0937\u093E \u0930\u092E\u093E \u092C\u094D\u0930\u0939\u094D\u092E\u0903 \u0924\u094D\u0930\u093F\u0935\u0943\u0924\u094D\u0938\u094D\u0935\u0930\u0903 \u0965\u0967\u0965</p><p class="trans">atha paippal\u0101do bhagav\u0101nbho kim\u0101dau ki\u1E41 j\u0101tamiti \u0964<br> sadyo j\u0101tamiti \u0964<br> ki\u1E41 bhagava iti \u0964<br> aghora iti \u0964<br> ki\u1E41 bhagava iti \u0964<br> v\u0101madeva iti \u0964<br> ki\u1E41 v\u0101 punarime bhagava iti \u0964<br> tatpuru\u1E63a iti \u0964<br> ki\u1E41 v\u0101 punarime bhagava iti \u0964<br> sarve\u1E63\u0101\u1E41 divy\u0101n\u0101\u1E41 prerayit\u0101 \u012B\u015B\u0101na iti \u0964<br> \u012B\u015B\u0101no bh\u016Btabhavyasya sarve\u1E63\u0101\u1E41 devayogin\u0101m \u0964<br> kati var\u1E47\u0101\u1E25 \u0964<br> kati bhed\u0101\u1E25 \u0964<br> kati \u015Baktaya\u1E25 \u0964<br> yatsarva\u1E41 tadguhyam \u0964<br> tasmai namo mah\u0101dev\u0101ya mah\u0101rudr\u0101ya prov\u0101ca tasmai bhagav\u0101nmahe\u015Ba\u1E25 \u0964<br> gopy\u0101dgopyatara\u1E41 loke yadyasti \u015Bru\u1E47u \u015B\u0101kala \u0964<br> sadyo j\u0101ta\u1E41 mah\u012B p\u016B\u1E63\u0101 ram\u0101 brahma\u1E25 triv\u1E5Btsvara\u1E25 \u09651\u0965</p><p>\u0417\u0430\u0442\u0435\u043C \u041F\u0430\u0439\u043F\u043F\u0430\u043B\u0430\u0434\u0430 (\u043E\u0431\u0440\u0430\u0442\u0438\u043B\u0441\u044F \u043A \u0413\u043E\u0441\u043F\u043E\u0434\u0443) \u0438 \u0441\u043A\u0430\u0437\u0430\u043B: \u041E, \u0413\u043E\u0441\u043F\u043E\u0434\u044C, \u041A\u0442\u043E \u0431\u044B\u043B \u0440\u043E\u0436\u0434\u0451\u043D \u043F\u0440\u0435\u0436\u0434\u0435 (\u0432\u0441\u0435\u0445)? \u2014 \u0421\u0430\u0434\u044C\u043E\u0434\u0436\u0430\u0442\u0430. \u2014 \u041A\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C? \u2014 \u0410\u0433\u0445\u043E\u0440\u0430. \u2014 \u041A\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C? \u2014 \u0412\u0430\u043C\u0430\u0434\u0435\u0432\u0430. \u2014 \u041A\u0442\u043E \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u044D\u0442\u0438\u0445 \u0434\u0432\u0443\u0445? \u2014 \u0422\u0430\u0442\u043F\u0443\u0440\u0443\u0448\u0430. \u2014 \u041A\u0442\u043E \u0435\u0449\u0451 \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u044D\u0442\u0438\u0445 \u0434\u0432\u0443\u0445? \u2014 \u0418\u0448\u0430\u043D\u0430, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432. \u0418\u0448\u0430\u043D\u0430 (\u0412\u043B\u0430\u0434\u044B\u043A\u0430) \u043F\u0440\u043E\u0448\u043B\u043E\u0433\u043E \u0438 \u0431\u0443\u0434\u0443\u0449\u0435\u0433\u043E, \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432 \u0438 \u0439\u043E\u0433\u0438\u043D\u043E\u0432. (\u041F\u0430\u0439\u043F\u043F\u0430\u043B\u0430\u0434\u0430 \u0441\u043F\u0440\u043E\u0441\u0438\u043B): \u041A\u0430\u043A\u043E\u0432\u044B \u0438\u0445 \u0446\u0432\u0435\u0442\u0430, \u043A\u0430\u043A\u043E\u0432\u044B \u0438\u0445 \u043E\u0442\u043B\u0438\u0447\u0438\u044F, \u043A\u0430\u043A\u043E\u0432\u044B \u0428\u0430\u043A\u0442\u0438? \u0412\u0441\u0435 \u044D\u0442\u043E \u0442\u0430\u0439\u043D\u043E\u0435 (\u043F\u043E\u0432\u0435\u0434\u0430\u0439 \u043C\u043D\u0435). \u041F\u043E\u043A\u043B\u043E\u043D\u0435\u043D\u0438\u0435 \u0422\u043E\u043C\u0443 \u041C\u0430\u0445\u0430\u0434\u0435\u0432\u0435, \u0412\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0420\u0443\u0434\u0440\u0435!\u041D\u0430 \u044D\u0442\u043E \u0435\u043C\u0443 \u043E\u0442\u0432\u0435\u0442\u0438\u043B \u0413\u043E\u0441\u043F\u043E\u0434\u044C \u041C\u0430\u0445\u0435\u0448\u0430.\u0421\u043B\u0443\u0448\u0430\u0439, \u0428\u0430\u043A\u0430\u043B\u0430 (\u043F\u043E\u0432\u0435\u0434\u0430\u044E \u0442\u0435\u0431\u0435) \u0442\u043E, \u0447\u0442\u043E \u0435\u0441\u0442\u044C \u043D\u0430\u0438\u0431\u043E\u043B\u0435\u0435 \u0441\u043E\u043A\u0440\u043E\u0432\u0435\u043D\u043D\u043E\u0435 \u0432 \u043C\u0438\u0440\u0435. \u0421\u0430\u0434\u044C\u043E\u0434\u0436\u0430\u0442\u0430 \u2014 \u0435\u0441\u0442\u044C \u0437\u0435\u043C\u043B\u044F, \u041F\u0443\u0448\u0430\u043D, \u0420\u0430\u043C\u0430, \u0411\u0440\u0430\u0445\u043C\u0430, \u0442\u0440\u043E\u0439\u043D\u0430\u044F \u0441\u0432\u0430\u0440\u0430 (\u0442\u0440\u0438 \u0432\u0438\u0434\u0430 \u0432\u0435\u0434\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u0443\u0434\u0430\u0440\u0435\u043D\u0438\u044F),</p></div><div class="stanza"><a href="#s2" id="s2" class="num">2</a><p class="sans">\u090B\u0917\u094D\u0935\u0947\u0926\u094B \u0917\u093E\u0930\u094D\u0939\u092A\u0924\u094D\u092F\u0902 \u091A \u092E\u0928\u094D\u0924\u094D\u0930\u093E\u0903 \u0938\u092A\u094D\u0924\u0938\u094D\u0935\u0930\u093E\u0938\u094D\u0924\u0925\u093E \u0964<br> \u0935\u0930\u094D\u0923\u0902 \u092A\u0940\u0924\u0902 \u0915\u094D\u0930\u093F\u092F\u093E \u0936\u0915\u094D\u0924\u093F\u0903 \u0938\u0930\u094D\u0935\u093E\u092D\u0940\u0937\u094D\u091F\u092B\u0932\u092A\u094D\u0930\u0926\u092E\u094D \u0965\u0968\u0965</p><p class="trans">\u1E5Bgvedo g\u0101rhapatya\u1E41 ca mantr\u0101\u1E25 saptasvar\u0101stath\u0101 \u0964<br> var\u1E47a\u1E41 p\u012Bta\u1E41 kriy\u0101 \u015Bakti\u1E25 sarv\u0101bh\u012B\u1E63\u1E6Daphalapradam \u09652\u0965</p><p>\u0420\u0438\u0433\u0432\u0435\u0434\u0430, \u043E\u0433\u043E\u043D\u044C \u0433\u0430\u0440\u0445\u0430\u043F\u0430\u0442\u044C\u044F, \u043C\u0430\u043D\u0442\u0440\u044B, \u0441\u0435\u043C\u044C \u0433\u043B\u0430\u0441\u043D\u044B\u0445, \u0436\u0451\u043B\u0442\u044B\u0439 \u0446\u0432\u0435\u0442 \u0438 \u043A\u0440\u0438\u044F \u0448\u0430\u043A\u0442\u0438 \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0430\u044F \u0432\u0441\u0435\u043C \u0436\u0435\u043B\u0430\u043D\u043D\u044B\u043C.</p></div><div class="stanza"><a href="#s3" id="s3" class="num">3</a><p class="sans">\u0905\u0918\u094B\u0930\u0902 \u0938\u0932\u093F\u0932\u0902 \u091A\u0928\u094D\u0926\u094D\u0930\u0902 \u0917\u094C\u0930\u0940 \u0935\u0947\u0926 \u0926\u094D\u0935\u093F\u0924\u0940\u092F\u0915\u092E\u094D \u0964<br> \u0928\u0940\u0930\u094D\u0926\u093E\u092D\u0902 \u0938\u094D\u0935\u0930\u0902 \u0938\u093E\u0928\u094D\u0926\u094D\u0930\u0902 \u0926\u0915\u094D\u0936\u093F\u0923\u093E\u0917\u094D\u0928\u093F\u0930\u0941\u0926\u093E\u0939\u0943\u0924\u092E\u094D \u0965\u0969\u0965</p><p class="trans">aghora\u1E41 salila\u1E41 candra\u1E41 gaur\u012B veda dvit\u012Byakam \u0964<br> n\u012Brd\u0101bha\u1E41 svara\u1E41 s\u0101ndra\u1E41 dak\u015Bi\u1E47\u0101gnirud\u0101h\u1E5Btam \u09653\u0965</p><p>\u0410\u0433\u0445\u043E\u0440\u0430 \u2013 [\u044D\u0442\u043E] \u0432\u043E\u0434\u0430, \u043B\u0443\u043D\u0430, \u0413\u0430\u0443\u0440\u0438, \u0432\u0442\u043E\u0440\u0430\u044F (\u042F\u0434\u0436\u0443\u0440) \u0412\u0435\u0434\u0430, \u043D\u0438\u0440\u0434\u0430\u0431\u0445\u0430, \u0441\u0432\u0430\u0440\u0430, \u0441\u0430\u043D\u0434\u0440\u0430, \u0434\u0430\u043A\u0448\u0438\u043D\u0430-\u0430\u0433\u043D\u0438,</p></div><div class="stanza"><a href="#s4" id="s4" class="num">4</a><p class="sans">\u092A\u091E\u094D\u091A\u093E\u0936\u0926\u094D\u0935\u0930\u094D\u0923\u0938\u0902\u092F\u0941\u0915\u094D\u0924\u0902 \u0938\u094D\u0925\u093F\u0924\u093F\u0930\u093F\u091A\u094D\u091B\u0915\u094D\u0930\u093F\u092F\u093E\u0928\u094D\u0935\u093F\u0924\u092E\u094D \u0964<br> \u0936\u0915\u094D\u0924\u093F\u0930\u0915\u094D\u0936\u0923\u0938\u0902\u092F\u0941\u0915\u094D\u0924\u0902 \u0938\u0930\u094D\u0935\u093E\u0918\u094C\u0918\u0935\u093F\u0928\u093E\u0936\u0928\u092E\u094D \u0965\u096A\u0965</p><p class="trans">pa\xF1c\u0101\u015Badvar\u1E47asa\u1E41yukta\u1E41 sthitiricchakriy\u0101nvitam \u0964<br> \u015Baktirak\u015Ba\u1E47asa\u1E41yukta\u1E41 sarv\u0101ghaughavin\u0101\u015Banam \u09654\u0965</p><p>\u0421\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u0441 \u043F\u044F\u0442\u044C\u044E\u0434\u0435\u0441\u044F\u0442\u044C\u044E \u0431\u0443\u043A\u0432\u0430\u043C\u0438, \u043E\u0431\u043B\u0430\u0434\u0430\u044E\u0449\u0438\u0439 \u0441\u0438\u043B\u0430\u043C\u0438 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F, \u0432\u043E\u043B\u0438, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F, \u0438 \u0441\u0438\u043B\u043E\u0439 \u0437\u0430\u0449\u0438\u0442\u044B, \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0430\u044E\u0449\u0435\u0439 \u0432\u0441\u0435 \u0433\u0440\u0435\u0445\u0438,</p></div><div class="stanza"><a href="#s5" id="s5" class="num">5</a><p class="sans">\u0938\u0930\u094D\u0935\u0926\u0941\u0937\u094D\u091F\u092A\u094D\u0930\u0936\u092E\u0928\u0902 \u0938\u0930\u094D\u0935\u0948\u0936\u094D\u0935\u0930\u094D\u092F\u092B\u0932\u092A\u094D\u0930\u0926\u092E\u094D \u0964<br> \u0935\u093E\u092E\u0926\u0947\u0935 \u092E\u0939\u093E\u092C\u094B\u0927\u0926\u093E\u092F\u0915\u0902 \u092A\u093E\u0935\u0928\u093E\u0924\u094D\u092E\u0915\u092E\u094D \u0965\u096B\u0965</p><p class="trans">sarvadu\u1E63\u1E6Dapra\u015Bamana\u1E41 sarvai\u015Bvaryaphalapradam \u0964<br> v\u0101madeva mah\u0101bodhad\u0101yaka\u1E41 p\u0101van\u0101tmakam \u09655\u0965</p><p>\u0423\u0441\u0442\u0440\u0430\u043D\u044F\u044E\u0449\u0438\u0439 \u0432\u0441\u0451 \u0434\u0443\u0440\u043D\u043E\u0435, \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 \u0432\u0441\u0435 \u043F\u043B\u043E\u0434\u044B \u043C\u043E\u0433\u0443\u0449\u0435\u0441\u0442\u0432\u0430. \u0412\u0430\u043C\u0430\u0434\u0435\u0432\u0430, \u0434\u0430\u0440\u0443\u044E\u0449\u0438\u0439 \u0432\u0435\u043B\u0438\u043A\u0443\u044E \u043C\u0443\u0434\u0440\u043E\u0441\u0442\u044C, \u2014 [\u044D\u0442\u043E] \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043E\u0433\u043D\u044F</p></div><div class="stanza"><a href="#s6" id="s6" class="num">6</a><p class="sans">\u0935\u093F\u0926\u094D\u092F\u093E\u0932\u094B\u0915\u0938\u092E\u093E\u092F\u0941\u0915\u094D\u0924\u0902 \u092D\u093E\u0928\u0941\u0915\u094B\u091F\u093F\u0938\u092E\u092A\u094D\u0930\u092D\u092E\u094D \u0964<br> \u092A\u094D\u0930\u0938\u0928\u094D\u0928\u0902 \u0938\u093E\u092E\u0935\u0947\u0926\u093E\u0916\u094D\u092F\u0902 \u0928\u093E\u0928\u093E\u0937\u094D\u091F\u0915\u0938\u092E\u0928\u094D\u0935\u093F\u0924\u092E\u094D \u0965\u096C\u0965</p><p class="trans">vidy\u0101lokasam\u0101yukta\u1E41 bh\u0101nuko\u1E6Disamaprabham \u0964<br> prasanna\u1E41 s\u0101maved\u0101khya\u1E41 n\u0101n\u0101\u1E63\u1E6Dakasamanvitam \u09656\u0965</p><p>\u0421\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u0441 \u0432\u0438\u0434\u044C\u044F-\u043B\u043E\u043A\u043E\u0439, \u0441\u0438\u044F\u044E\u0449\u0438\u0439, \u043F\u043E\u0434\u043E\u0431\u043D\u043E \u0434\u0435\u0441\u044F\u0442\u0438 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u0430\u043C \u0441\u043E\u043B\u043D\u0446, \u0443\u0434\u043E\u0432\u043B\u0435\u0442\u0432\u043E\u0440\u0451\u043D\u043D\u044B\u0439, \u0438\u043C\u0435\u043D\u0443\u0435\u043C\u044B\u0439 \u0421\u0430\u043C\u0430\u0432\u0435\u0434\u043E\u0439, \u0432\u043C\u0435\u0449\u0430\u044E\u0449\u0438\u0439 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u043E \u0432\u043E\u0441\u044C\u043C\u0451\u0440\u043E\u043A.</p></div><div class="stanza"><a href="#s7" id="s7" class="num">7</a><p class="sans">\u0927\u0940\u0930\u0938\u094D\u0935\u0930\u092E\u0927\u0940\u0928\u0902 \u091A\u093E\u0935\u0939\u0928\u0940\u092F\u092E\u0928\u0941\u0924\u094D\u0924\u092E\u092E\u094D \u0964<br> \u091C\u094D\u091E\u093E\u0928\u0938\u0902\u0939\u093E\u0930\u0938\u0902\u092F\u0941\u0915\u094D\u0924\u0902 \u0936\u0915\u094D\u0924\u093F\u0926\u094D\u0935\u092F\u0938\u092E\u0928\u094D\u0935\u093F\u0924\u092E\u094D \u0965\u096D\u0965</p><p class="trans">dh\u012Brasvaramadh\u012Bna\u1E41 c\u0101vahan\u012Byamanuttamam \u0964<br> j\xF1\u0101nasa\u1E41h\u0101rasa\u1E41yukta\u1E41 \u015Baktidvayasamanvitam \u09657\u0965</p><p>\u041F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0434\u043E\u043B\u0433\u043E\u0439 \u0433\u043B\u0430\u0441\u043D\u043E\u0439, \u043E\u0433\u043D\u0451\u043C \u0430\u0445\u0430\u0432\u0430\u043D\u0438\u044F, \u0432\u043C\u0435\u0449\u0430\u044E\u0449\u0438\u0439 \u0432 \u0441\u0435\u0431\u044F \u0434\u0432\u0435 \u0448\u0430\u043A\u0442\u0438 \u2014 \u0437\u043D\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u044F,</p></div><div class="stanza"><a href="#s8" id="s8" class="num">8</a><p class="sans">\u0935\u0930\u094D\u0923\u0902 \u0936\u0941\u0915\u094D\u0932\u0902 \u0924\u092E\u094B\u092E\u093F\u0936\u094D\u0930\u0902 \u092A\u0942\u0930\u094D\u0923\u092C\u094B\u0927\u0915\u0930\u0902 \u0938\u094D\u0935\u092F\u092E\u094D \u0964<br> \u0927\u093E\u092E\u0924\u094D\u0930\u092F\u0928\u093F\u092F\u0928\u094D\u0924\u093E\u0930\u0902 \u0927\u093E\u092E\u0924\u094D\u0930\u092F\u0938\u092E\u0928\u094D\u0935\u093F\u0924\u092E\u094D \u0965\u096E\u0965</p><p class="trans">var\u1E47a\u1E41 \u015Bukla\u1E41 tamomi\u015Bra\u1E41 p\u016Br\u1E47abodhakara\u1E41 svayam \u0964<br> dh\u0101matrayaniyant\u0101ra\u1E41 dh\u0101matrayasamanvitam \u09658\u0965</p><p>\u0411\u0435\u043B\u044B\u0439 \u0446\u0432\u0435\u0442, \u0441\u043C\u0435\u0448\u0430\u043D\u043D\u044B\u0439 \u0441 \u0442\u044C\u043C\u043E\u0439, \u0434\u0435\u043B\u0430\u044E\u0449\u0438\u0439 \u0440\u0430\u0437\u0443\u043C \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u043C, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C \u0442\u0440\u0451\u0445 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0439 [\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F], \u0432\u043C\u0435\u0449\u0430\u044E\u0449\u0438\u0439 \u0442\u0440\u0438 \u043E\u0431\u0438\u0442\u0435\u043B\u0438,</p></div><div class="stanza"><a href="#s9" id="s9" class="num">9</a><p class="sans">\u0938\u0930\u094D\u0935\u0938\u094C\u092D\u093E\u0917\u094D\u092F\u0926\u0902 \u0928\u0944\u0923\u093E\u0902 \u0938\u0930\u094D\u0935\u0915\u0930\u094D\u092E\u092B\u0932\u092A\u094D\u0930\u0926\u092E\u094D \u0964<br> \u0905\u0937\u094D\u091F\u093E\u0915\u094D\u0936\u0930\u0938\u092E\u093E\u092F\u0941\u0915\u094D\u0924\u092E\u0937\u094D\u091F\u092A\u0924\u094D\u0930\u093E\u0928\u094D\u0924\u0930\u0938\u094D\u0925\u093F\u0924\u092E\u094D \u0965\u096F\u0965</p><p class="trans">sarvasaubh\u0101gyada\u1E41 n\u1E5D\u1E47\u0101\u1E41 sarvakarmaphalapradam \u0964<br> a\u1E63\u1E6D\u0101k\u015Barasam\u0101yuktama\u1E63\u1E6Dapatr\u0101ntarasthitam \u09659\u0965</p><p>\u0414\u0430\u044E\u0449\u0438\u0439 \u0432\u0441\u0435 \u0431\u043B\u0430\u0433\u0430 \u043B\u044E\u0434\u044F\u043C, \u043D\u0430\u0434\u0435\u043B\u044F\u044E\u0449\u0438\u0439 \u0432\u0441\u0435 \u0434\u0435\u044F\u043D\u0438\u044F \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u043E\u043C, \u0441\u0432\u044F\u0437\u0430\u043D\u043D\u044B\u0439 \u0441 \u0432\u043E\u0441\u044C\u043C\u044C\u044E \u0441\u043B\u043E\u0433\u0430\u043C\u0438, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432\u043D\u0443\u0442\u0440\u0438 \u0432\u043E\u0441\u044C\u043C\u0438 \u0441\u043E\u0441\u0443\u0434\u043E\u0432</p></div><div class="stanza"><a href="#s10" id="s10" class="num">10</a><p class="sans">\u092F\u0924\u094D\u0924\u0924\u094D\u092A\u0941\u0930\u0941\u0937\u0902 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0902 \u0935\u093E\u092F\u0941\u092E\u0923\u094D\u0921\u0932\u0938\u0902\u0935\u0943\u0924\u092E\u094D \u0964<br> \u092A\u091E\u094D\u091A\u093E\u0917\u094D\u0928\u093F\u0928\u093E \u0938\u092E\u093E\u092F\u0941\u0915\u094D\u0924\u0902 \u092E\u0928\u094D\u0924\u094D\u0930\u0936\u0915\u094D\u0924\u093F\u0928\u093F\u092F\u093E\u092E\u0915\u092E\u094D \u0965\u0967\u0966\u0965</p><p class="trans">yattatpuru\u1E63a\u1E41 prokta\u1E41 v\u0101yuma\u1E47\u1E0Dalasa\u1E41v\u1E5Btam \u0964<br> pa\xF1c\u0101gnin\u0101 sam\u0101yukta\u1E41 mantra\u015Baktiniy\u0101makam \u096510\u0965</p><p>\u0422\u043E\u0442, \u043A\u0442\u043E \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0422\u0430\u0442\u043F\u0443\u0440\u0443\u0448\u0430 \u0441\u0432\u044F\u0437\u0430\u043D \u0441 \u043E\u0431\u043B\u0430\u0441\u0442\u044C\u044E \u0432\u0435\u0442\u0440\u0430, \u0441\u0432\u044F\u0437\u0430\u043D \u0441 \u043F\u044F\u0442\u044C\u044E \u043E\u0433\u043D\u044F\u043C\u0438, \u043F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C \u0441\u0438\u043B\u044B \u043C\u0430\u043D\u0442\u0440,</p></div><div class="stanza"><a href="#s11" id="s11" class="num">11</a><p class="sans">\u092A\u091E\u094D\u091A\u093E\u0936\u0924\u094D\u0938\u094D\u0935\u0930\u0935\u0930\u094D\u0923\u093E\u0916\u094D\u092F\u092E\u0925\u0930\u094D\u0935\u0935\u0947\u0926\u0938\u094D\u0935\u0930\u0942\u092A\u0915\u092E\u094D \u0964<br> \u0915\u094B\u091F\u093F\u0915\u094B\u091F\u093F\u0917\u0923\u093E\u0927\u094D\u092F\u0915\u094D\u0936\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0923\u094D\u0921\u093E\u0916\u0923\u094D\u0921\u0935\u093F\u0917\u094D\u0930\u0939\u092E\u094D \u0965\u0967\u0967\u0965</p><p class="trans">pa\xF1c\u0101\u015Batsvaravar\u1E47\u0101khyamatharvavedasvar\u016Bpakam \u0964<br> ko\u1E6Diko\u1E6Diga\u1E47\u0101dhyak\u015Ba\u1E41 brahm\u0101\u1E47\u1E0D\u0101kha\u1E47\u1E0Davigraham \u096511\u0965</p><p>(\u041E\u043D) \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u044E\u0434\u0435\u0441\u044F\u0442\u044C\u044E \u0431\u0443\u043A\u0432\u0430\u043C\u0438, \u0433\u043B\u0430\u0441\u043D\u044B\u043C\u0438 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C\u0438, \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C\u044E \u0410\u0442\u0445\u0430\u0440\u0432\u0430 \u0412\u0435\u0434\u044B, \u0412\u043B\u0430\u0434\u044B\u043A\u043E\u0439 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u0438 \u043C\u0438\u043B\u043B\u0438\u043E\u043D\u043E\u0432 \u0433\u0430\u043D\u043E\u0432, \u0432\u043E\u043F\u043B\u043E\u0449\u0435\u043D\u0438\u0435\u043C \u0431\u0435\u0441\u043A\u043E\u043D\u0435\u0447\u043D\u043E\u0439 \u0431\u0440\u0430\u0445\u043C\u0430\u043D\u0434\u044B.</p></div><div class="stanza"><a href="#s12" id="s12" class="num">12</a><p class="sans">\u0935\u0930\u094D\u0923\u0902 \u0930\u0915\u094D\u0924\u0902 \u0915\u093E\u092E\u0926\u0902 \u091A \u0938\u0930\u094D\u0935\u093E\u0927\u093F\u0935\u094D\u092F\u093E\u0927\u093F\u092D\u0947\u0937\u091C\u092E\u094D \u0964<br> \u0938\u0943\u0937\u094D\u091F\u093F\u0938\u094D\u0925\u093F\u0924\u093F\u0932\u092F\u093E\u0926\u0940\u0928\u093E\u0902 \u0915\u093E\u0930\u0923\u0902 \u0938\u0930\u094D\u0935\u0936\u0915\u094D\u0924\u093F\u0927\u0943\u0915\u094D \u0965\u0967\u0968\u0965</p><p class="trans">var\u1E47a\u1E41 rakta\u1E41 k\u0101mada\u1E41 ca sarv\u0101dhivy\u0101dhibhe\u1E63ajam \u0964<br> s\u1E5B\u1E63\u1E6Disthitilay\u0101d\u012Bn\u0101\u1E41 k\u0101ra\u1E47a\u1E41 sarva\u015Baktidh\u1E5Bk \u096512\u0965</p><p>(\u0415\u0433\u043E) \u0446\u0432\u0435\u0442 \u2013 \u043A\u0440\u0430\u0441\u043D\u044B\u0439, \u041E\u043D \u2014 \u0438\u0441\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0438\u0439 \u0436\u0435\u043B\u0430\u043D\u0438\u044F, \u043B\u0435\u043A\u0430\u0440\u0441\u0442\u0432\u043E \u043E\u0442 \u0432\u0441\u0435\u0445 \u0431\u043E\u043B\u0435\u0437\u043D\u0435\u0439. \u041F\u0440\u0438\u0447\u0438\u043D\u0430 \u0442\u0432\u043E\u0440\u0435\u043D\u0438\u044F, \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0430\u043D\u0438\u044F \u0438 \u0440\u0430\u0437\u0440\u0443\u0448\u0435\u043D\u0438\u044F, \u0441\u043E\u0434\u0435\u0440\u0436\u0430\u0449\u0438\u0439 \u0432\u0441\u0435 \u0448\u0430\u043A\u0442\u0438.</p></div><div class="stanza"><a href="#s13" id="s13" class="num">13</a><p class="sans">\u0905\u0935\u0938\u094D\u0925\u093E\u0924\u094D\u0930\u093F\u0924\u092F\u093E\u0924\u0940\u0924\u0902 \u0924\u0941\u0930\u0940\u092F\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u0938\u0902\u091C\u094D\u091E\u093F\u0924\u092E\u094D \u0964<br> \u092C\u094D\u0930\u0939\u094D\u092E\u0935\u093F\u0937\u094D\u0923\u094D\u0935\u093E\u0926\u093F\u092D\u093F\u0903 \u0938\u0947\u0935\u094D\u092F\u0902 \u0938\u0930\u094D\u0935\u0947\u0937\u093E\u0902 \u091C\u0928\u0915\u0902 \u092A\u0930\u092E\u094D \u0965\u0967\u0969\u0965</p><p class="trans">avasth\u0101tritay\u0101t\u012Bta\u1E41 tur\u012Bya\u1E41 brahmasa\u1E41j\xF1itam \u0964<br> brahmavi\u1E63\u1E47v\u0101dibhi\u1E25 sevya\u1E41 sarve\u1E63\u0101\u1E41 janaka\u1E41 param \u096513\u0965</p><p>\u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u0442\u0443\u0440\u0438\u0439\u0438, \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0435\u0435 \u0442\u0440\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u044F (\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u044F), \u043F\u043E\u0437\u043D\u0430\u0451\u0442\u0441\u044F \u043A\u0430\u043A \u0411\u0440\u0430\u0445\u043C\u0430\u043D. \u041E\u043D \u2013 \u0432\u044B\u0441\u0448\u0438\u0439 \u041E\u0442\u0435\u0446 \u0432\u0441\u0435\u0445, \u043F\u043E\u0447\u0438\u0442\u0430\u0435\u043C\u044B\u0439 \u0411\u0440\u0430\u0445\u043C\u043E\u0439, \u0412\u0438\u0448\u043D\u0443 \u0438 \u043F\u0440\u043E\u0447\u0438\u043C\u0438.</p></div><div class="stanza"><a href="#s14" id="s14" class="num">14</a><p class="sans">\u0908\u0936\u093E\u0928\u0902 \u092A\u0930\u092E\u0902 \u0935\u093F\u0926\u094D\u092F\u093E\u0924\u094D\u092A\u094D\u0930\u0947\u0930\u0915\u0902 \u092C\u0941\u0926\u094D\u0927\u093F\u0938\u093E\u0915\u094D\u0936\u093F\u0923\u092E\u094D \u0964<br> \u0906\u0915\u093E\u0936\u093E\u0924\u094D\u092E\u0915\u092E\u0935\u094D\u092F\u0915\u094D\u0924\u092E\u094B\u0919\u094D\u0915\u093E\u0930\u0938\u094D\u0935\u0930\u092D\u0942\u0937\u093F\u0924\u092E\u094D \u0965\u0967\u096A\u0965</p><p class="trans">\u012B\u015B\u0101na\u1E41 parama\u1E41 vidy\u0101tpreraka\u1E41 buddhis\u0101k\u015Bi\u1E47am \u0964<br> \u0101k\u0101\u015B\u0101tmakamavyaktamo\u1E45k\u0101rasvarabh\u016B\u1E63itam \u096514\u0965</p><p>\u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0418\u0448\u0430\u043D\u0443 \u0441\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u043D\u0430\u0442\u044C \u043A\u0430\u043A \u041F\u0440\u0430\u0432\u0438\u0442\u0435\u043B\u044F, \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044F \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0430, \u043D\u0435\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u043D\u044B\u0439 \u0443\u043A\u0440\u0430\u0448\u0435\u043D\u043D\u044B\u0439 \u0441\u0432\u0430\u0440\u043E\u0439 \u0441\u043B\u043E\u0433 \u041E\u041C.</p></div><div class="stanza"><a href="#s15" id="s15" class="num">15</a><p class="sans">\u0938\u0930\u094D\u0935\u0926\u0947\u0935\u092E\u092F\u0902 \u0936\u093E\u0928\u094D\u0924\u0902 \u0936\u093E\u0928\u094D\u0924\u094D\u092F\u0924\u0940\u0924\u0902 \u0938\u094D\u0935\u0930\u093E\u0926\u094D\u092C\u0939\u093F\u0903 \u0964<br> \u0905\u0915\u093E\u0930\u093E\u0926\u093F\u0938\u094D\u0935\u0930\u093E\u0927\u094D\u092F\u0915\u094D\u0936\u092E\u093E\u0915\u093E\u0936\u092E\u092F\u0935\u093F\u0917\u094D\u0930\u0939\u092E\u094D \u0965\u0967\u096B\u0965</p><p class="trans">sarvadevamaya\u1E41 \u015B\u0101nta\u1E41 \u015B\u0101ntyat\u012Bta\u1E41 svar\u0101dbahi\u1E25 \u0964<br> ak\u0101r\u0101disvar\u0101dhyak\u015Bam\u0101k\u0101\u015Bamayavigraham \u096515\u0965</p><p>\u0421\u043E\u0441\u0442\u043E\u044F\u0449\u0438\u0439 \u0438\u0437 \u0432\u0441\u0435\u0445 \u0431\u043E\u0433\u043E\u0432, \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u044E\u0449\u0438\u0439 \u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u043E\u043A\u043E\u044F \u0438 \u043F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F\u0449\u0438\u0439 \u043F\u043E\u043A\u043E\u0439, [\u043D\u0430\u0445\u043E\u0434\u044F\u0449\u0438\u0439\u0441\u044F] \u043F\u043E \u0442\u0443 \u0441\u0442\u043E\u0440\u043E\u043D\u0443 \u043C\u0438\u0440\u043E\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u044F. \u041F\u043E\u0432\u0435\u043B\u0438\u0442\u0435\u043B\u044C \u0433\u043B\u0430\u0441\u043D\u044B\u0445, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0410, \u0444\u043E\u0440\u043C\u0430, \u0437\u0430\u043F\u043E\u043B\u043D\u044F\u044E\u0449\u0430\u044F \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E.</p></div><div class="stanza"><a href="#s16" id="s16" class="num">16</a><p class="sans">\u092A\u091E\u094D\u091A\u0915\u0943\u0924\u094D\u092F\u0928\u093F\u092F\u0928\u094D\u0924\u093E\u0930\u0902 \u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u0915\u0902 \u092C\u0943\u0939\u0924\u094D \u0964<br> \u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u094B\u092A\u0938\u0902\u0939\u093E\u0930\u0902 \u0915\u0943\u0924\u094D\u0935\u093E \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u0938\u0902\u0938\u094D\u0925\u093F\u0924\u0903 \u0965\u0967\u096C\u0965</p><p class="trans">pa\xF1cak\u1E5Btyaniyant\u0101ra\u1E41 pa\xF1cabrahm\u0101tmaka\u1E41 b\u1E5Bhat \u0964<br> pa\xF1cabrahmopasa\u1E41h\u0101ra\u1E41 k\u1E5Btv\u0101 sv\u0101tmani sa\u1E41sthita\u1E25 \u096516\u0965</p><p>\u0423\u043F\u0440\u0430\u0432\u043B\u044F\u044E\u0449\u0438\u0439 \u043F\u044F\u0442\u044C\u044E \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F\u043C\u0438, \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u044F\u0442\u0438 \u0411\u0440\u0430\u0445\u043C, \u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0410\u0442\u043C\u0430\u043D\u0435.</p></div><div class="stanza"><a href="#s17" id="s17" class="num">17</a><p class="sans">\u0938\u094D\u0935\u092E\u093E\u092F\u093E\u0935\u0948\u092D\u0935\u093E\u0928\u094D\u0938\u0930\u094D\u0935\u093E\u0928\u094D\u0938\u0902\u0939\u0943\u0924\u094D\u092F \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u0938\u094D\u0925\u093F\u0924\u0903 \u0964<br> \u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u0915\u093E\u0924\u0940\u0924\u094B \u092D\u093E\u0938\u0924\u0947 \u0938\u094D\u0935\u0938\u094D\u0935\u0924\u0947\u091C\u0938\u093E \u0965\u0967\u096D\u0965</p><p class="trans">svam\u0101y\u0101vaibhav\u0101nsarv\u0101nsa\u1E41h\u1E5Btya sv\u0101tmani sthita\u1E25 \u0964<br> pa\xF1cabrahm\u0101tmak\u0101t\u012Bto bh\u0101sate svasvatejas\u0101 \u096517\u0965</p><p>\u0421\u0432\u0451\u0440\u0442\u044B\u0432\u0430\u044F \u0432\u0441\u0435 \u0441\u0438\u043B\u043E\u0439 \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 \u041C\u0430\u0439\u0438, \u041E\u043D \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0432 \u0441\u0430\u043C\u043E\u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E\u0441\u0442\u0438 \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u043C \u0410\u0442\u043C\u0430\u043D\u0435. \u041F\u0440\u0435\u0432\u043E\u0441\u0445\u043E\u0434\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u044F\u0442\u0438 [\u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0439] \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u041E\u043D \u0441\u0438\u044F\u0435\u0442 \u0421\u0432\u043E\u0438\u043C \u0421\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u0421\u0432\u0435\u0442\u043E\u043C.</p></div><div class="stanza"><a href="#s18" id="s18" class="num">18</a><p class="sans">\u0906\u0926\u093E\u0935\u0928\u094D\u0924\u0947 \u091A \u092E\u0927\u094D\u092F\u0947 \u091A \u092D\u093E\u0938\u0938\u0947 \u0928\u093E\u0928\u094D\u092F\u0939\u0947\u0924\u0941\u0928\u093E \u0964<br> \u092E\u093E\u092F\u092F\u093E \u092E\u094B\u0939\u093F\u0924\u093E\u0903 \u0936\u092E\u094D\u092D\u094B\u0930\u094D\u092E\u0939\u093E\u0926\u0947\u0935\u0902 \u091C\u0917\u0926\u094D\u0917\u0941\u0930\u0941\u092E\u094D \u0965\u0967\u096E\u0965</p><p class="trans">\u0101d\u0101vante ca madhye ca bh\u0101sase n\u0101nyahetun\u0101 \u0964<br> m\u0101yay\u0101 mohit\u0101\u1E25 \u015Bambhormah\u0101deva\u1E41 jagadgurum \u096518\u0965</p><p>\u0412 \u043D\u0430\u0447\u0430\u043B\u0435, \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0438 \u043A\u043E\u043D\u0446\u0435 \u043E\u043D \u0441\u0432\u0435\u0442\u0438\u0442 (\u0421\u0432\u043E\u0438\u043C \u0421\u0432\u0435\u0442\u043E\u043C), \u0430 \u043D\u0435 \u043E\u0442 \u043A\u0430\u043A\u043E\u0433\u043E-\u043B\u0438\u0431\u043E \u0438\u043D\u043E\u0433\u043E \u0438\u0441\u0442\u043E\u0447\u043D\u0438\u043A\u0430. \u0412\u0432\u0435\u0434\u0451\u043D\u043D\u044B\u0435 \u0432 \u0437\u0430\u0431\u043B\u0443\u0436\u0434\u0435\u043D\u0438\u0435 \u043C\u0430\u0439\u0435\u0439 \u0428\u0430\u043C\u0431\u0445\u0443, \u0423\u0447\u0438\u0442\u0435\u043B\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u043E\u0439,</p></div><div class="stanza"><a href="#s19" id="s19" class="num">19</a><p class="sans">\u0928 \u091C\u093E\u0928\u0928\u094D\u0924\u093F \u0938\u0941\u0930\u093E\u0903 \u0938\u0930\u094D\u0935\u0947 \u0938\u0930\u094D\u0935\u0915\u093E\u0930\u0923\u0915\u093E\u0930\u0923\u092E\u094D \u0964<br> \u0928 \u0938\u0928\u094D\u0926\u0943\u0936\u0947 \u0924\u093F\u0937\u094D\u0920\u0924\u093F \u0930\u0942\u092A\u092E\u0938\u094D\u092F \u092A\u0930\u093E\u0924\u094D\u092A\u0930\u0902 \u092A\u0941\u0930\u0941\u0937\u0902 \u0935\u093F\u0936\u094D\u0935\u0927\u093E\u092E \u0965\u0967\u096F\u0965</p><p class="trans">na j\u0101nanti sur\u0101\u1E25 sarve sarvak\u0101ra\u1E47ak\u0101ra\u1E47am \u0964<br> na sand\u1E5B\u015Be ti\u1E63\u1E6Dhati r\u016Bpamasya par\u0101tpara\u1E41 puru\u1E63a\u1E41 vi\u015Bvadh\u0101ma \u096519\u0965</p><p>\u0412\u0441\u0435 \u0431\u043E\u0433\u0438 \u043D\u0435 \u0437\u043D\u0430\u044E\u0442 \u0415\u0433\u043E, \u041F\u0440\u0438\u0447\u0438\u043D\u0443 \u0432\u0441\u0435\u0445 \u043F\u0440\u0438\u0447\u0438\u043D. \u041F\u043E\u0434\u043E\u0431\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u043D\u0435\u0442 \u043D\u0438 \u0443 \u043A\u043E\u0433\u043E \u043A\u0440\u043E\u043C\u0435 \u041F\u0443\u0440\u0443\u0448\u0438, \u0412\u0441\u0435\u043B\u0435\u043D\u0441\u043A\u043E\u0439 \u043E\u0431\u0438\u0442\u0435\u043B\u0438, \u043F\u0440\u0435\u0432\u044B\u0448\u0430\u044E\u0449\u0435\u0433\u043E \u0432\u0441\u0435.</p></div><div class="stanza"><a href="#s20" id="s20" class="num">20</a><p class="sans">\u092F\u0947\u0928 \u092A\u094D\u0930\u0915\u093E\u0936\u0924\u0947 \u0935\u093F\u0936\u094D\u0935\u0902 \u092F\u0924\u094D\u0930\u0948\u0935 \u092A\u094D\u0930\u0935\u093F\u0932\u0940\u092F\u0924\u0947 \u0964<br> \u0924\u0926\u094D\u092C\u094D\u0930\u0939\u094D\u092E \u092A\u0930\u092E\u0902 \u0936\u093E\u0928\u094D\u0924\u0902 \u0924\u0926\u094D\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0938\u094D\u092E\u093F \u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D \u0965\u0968\u0966\u0965</p><p class="trans">yena prak\u0101\u015Bate vi\u015Bva\u1E41 yatraiva pravil\u012Byate \u0964<br> tadbrahma parama\u1E41 \u015B\u0101nta\u1E41 tadbrahm\u0101smi parama\u1E41 padam \u096520\u0965</p><p>\u041A\u0435\u043C \u0432\u0441\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438 \u0432 \u041A\u043E\u043C \u0432\u0441\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u044F\u0435\u0442\u0441\u044F, \u0422\u043E\u0442 \u2013 \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u0412\u044B\u0441\u0448\u0438\u0439 \u043F\u043E\u043A\u043E\u0439. \u042F \u0435\u0441\u0442\u044C \u0411\u0440\u0430\u0445\u043C\u0430\u043D, \u0432\u0435\u0447\u043D\u0430\u044F \u041E\u0431\u0438\u0442\u0435\u043B\u044C.</p></div><div class="stanza"><a href="#s21" id="s21" class="num">21</a><p class="sans">\u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E \u092A\u0930\u0902 \u0935\u093F\u0926\u094D\u092F\u093E\u0924\u094D\u0938\u0926\u094D\u092F\u094B\u091C\u093E\u0924\u093E\u0926\u093F\u092A\u0942\u0930\u094D\u0935\u0915\u092E\u094D \u0964<br> \u0926\u0943\u0936\u094D\u092F\u0924\u0947 \u0936\u094D\u0930\u0942\u092F\u0924\u0947 \u092F\u091A\u094D\u091A \u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u0915\u0902 \u0938\u094D\u0935\u092F\u092E\u094D \u0965\u0968\u0967\u0965</p><p class="trans">pa\xF1cabrahma para\u1E41 vidy\u0101tsadyoj\u0101t\u0101dip\u016Brvakam \u0964<br> d\u1E5B\u015Byate \u015Br\u016Byate yacca pa\xF1cabrahm\u0101tmaka\u1E41 svayam \u096521\u0965</p><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u043E\u0437\u043D\u0430\u0442\u044C \u044D\u0442\u0438 \u043F\u044F\u0442\u044C \u0411\u0440\u0430\u0445\u043C, \u043D\u0430\u0447\u0438\u043D\u0430\u044F \u0441 \u0421\u0430\u0434\u044C\u043E\u0434\u0436\u0430\u0442\u044B. (\u0412\u0441\u0435), \u0447\u0442\u043E \u0432\u0438\u0434\u0438\u0442\u0441\u044F \u0438 \u0441\u043B\u044B\u0448\u0438\u0442\u0441\u044F \u0435\u0441\u0442\u044C \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u044F\u0442\u0438 \u0411\u0440\u0430\u0445\u043C.</p></div><div class="stanza"><a href="#s22" id="s22" class="num">22</a><p class="sans">\u092A\u091E\u094D\u091A\u0927\u093E \u0935\u0930\u094D\u0924\u092E\u093E\u0928\u0902 \u0924\u0902 \u092C\u094D\u0930\u0939\u094D\u092E\u0915\u093E\u0930\u094D\u092F\u092E\u093F\u0924\u093F \u0938\u094D\u092E\u0943\u0924\u092E\u094D \u0964<br> \u092C\u094D\u0930\u0939\u094D\u092E\u0915\u093E\u0930\u094D\u092F\u092E\u093F\u0924\u093F \u091C\u094D\u091E\u093E\u0924\u094D\u0935\u093E \u0908\u0936\u093E\u0928\u0902 \u092A\u094D\u0930\u0924\u093F\u092A\u0926\u094D\u092F\u0924\u0947 \u0965\u0968\u0968\u0965</p><p class="trans">pa\xF1cadh\u0101 vartam\u0101na\u1E41 ta\u1E41 brahmak\u0101ryamiti sm\u1E5Btam \u0964<br> brahmak\u0101ryamiti j\xF1\u0101tv\u0101 \u012B\u015B\u0101na\u1E41 pratipadyate \u096522\u0965</p><p>\u041F\u044F\u0442\u044C \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0439, \u0441\u0447\u0438\u0442\u0430\u044E\u0442\u0441\u044F \u043F\u044F\u0442\u044C\u044E \u043E\u0431\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044F\u043C\u0438 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430. \u041F\u043E\u0437\u043D\u0430\u0432 \u043E\u0431\u044F\u0437\u0430\u043D\u043D\u043E\u0441\u0442\u044C \u043F\u044F\u0442\u0438 \u0411\u0440\u0430\u0445\u043C, \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442\u0441\u044F \u0418\u0448\u0430\u043D\u0430.</p></div><div class="stanza"><a href="#s23" id="s23" class="num">23</a><p class="sans">\u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u0915\u0902 \u0938\u0930\u094D\u0935\u0902 \u0938\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u092A\u094D\u0930\u0935\u093F\u0932\u093E\u092A\u094D\u092F \u091A \u0964<br> \u0938\u094B\u093D\u0939\u092E\u0938\u094D\u092E\u0940\u0924\u093F \u091C\u093E\u0928\u0940\u092F\u093E\u0926\u094D\u0935\u093F\u0926\u094D\u0935\u093E\u0928\u094D\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u093D\u092E\u0943\u0924\u094B \u092D\u0935\u0947\u0924\u094D \u0965\u0968\u0969\u0965</p><p class="trans">pa\xF1cabrahm\u0101tmaka\u1E41 sarva\u1E41 sv\u0101tmani pravil\u0101pya ca \u0964<br> so&#39;hamasm\u012Bti j\u0101n\u012By\u0101dvidv\u0101nbrahm\u0101&#39;m\u1E5Bto bhavet \u096523\u0965</p><p>\u041F\u043E\u0433\u0440\u0443\u0437\u0438\u0432 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0432\u0441\u0435\u0445 \u043F\u044F\u0442\u0438 \u0411\u0440\u0430\u0445\u043C \u0432 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u0410\u0442\u043C\u0430\u043D \u0437\u043D\u0430\u044E\u0449\u0438\u0439 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 [\u0438 \u0443\u0442\u0432\u0435\u0440\u0436\u0434\u0430\u044E\u0449\u0438\u0439]: \xAB\u041E\u043D \u2013 \u0435\u0441\u0442\u044C \u042F\xBB \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u043D\u044B\u043C.</p></div><div class="stanza"><a href="#s24" id="s24" class="num">24</a><p class="sans">\u0907\u0924\u094D\u092F\u0947\u0924\u0926\u094D\u092C\u094D\u0930\u0939\u094D\u092E \u091C\u093E\u0928\u0940\u092F\u093E\u0926\u094D\u092F\u0903 \u0938 \u092E\u0941\u0915\u094D\u0924\u094B \u0928 \u0938\u0902\u0936\u092F\u0903 \u0964<br> \u092A\u091E\u094D\u091A\u093E\u0915\u094D\u0936\u0930\u092E\u092F\u0902 \u0936\u092E\u094D\u092D\u0941\u0902 \u092A\u0930\u092C\u094D\u0930\u0939\u094D\u092E\u0938\u094D\u0935\u0930\u0942\u092A\u093F\u0923\u092E\u094D \u0965\u0968\u096A\u0965</p><p class="trans">ityetadbrahma j\u0101n\u012By\u0101dya\u1E25 sa mukto na sa\u1E41\u015Baya\u1E25 \u0964<br> pa\xF1c\u0101k\u015Baramaya\u1E41 \u015Bambhu\u1E41 parabrahmasvar\u016Bpi\u1E47am \u096524\u0965</p><p>\u041A\u0442\u043E \u0437\u043D\u0430\u0435\u0442 \u0442\u0430\u043A \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430, \u0442\u043E\u0442 \u2013 \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0451\u043D\u043D\u044B\u0439, \u0431\u0435\u0437 \u0441\u043E\u043C\u043D\u0435\u043D\u0438\u044F. \u041F\u043E\u0437\u043D\u0430\u0432 \u0428\u0430\u043C\u0431\u0445\u0443, \u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0438\u0437 \u043F\u044F\u0442\u0438 \u0441\u043B\u043E\u0433\u043E\u0432, \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u0412\u044B\u0441\u0448\u0435\u0433\u043E \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430</p></div><div class="stanza"><a href="#s25" id="s25" class="num">25</a><p class="sans">\u0928\u0915\u093E\u0930\u093E\u0926\u093F\u092F\u0915\u093E\u0930\u093E\u0928\u094D\u0924\u0902 \u091C\u094D\u091E\u093E\u0924\u094D\u0935\u093E \u092A\u091E\u094D\u091A\u093E\u0915\u094D\u0936\u0930\u0902 \u091C\u092A\u0947\u0924\u094D \u0964<br> \u0938\u0930\u094D\u0935\u0902 \u092A\u091E\u094D\u091A\u093E\u0924\u094D\u092E\u0915\u0902 \u0935\u093F\u0926\u094D\u092F\u093E\u0924\u094D\u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u0924\u0924\u094D\u0924\u094D\u0935\u0924\u0903 \u0965\u0968\u096B\u0965</p><p class="trans">nak\u0101r\u0101diyak\u0101r\u0101nta\u1E41 j\xF1\u0101tv\u0101 pa\xF1c\u0101k\u015Bara\u1E41 japet \u0964<br> sarva\u1E41 pa\xF1c\u0101tmaka\u1E41 vidy\u0101tpa\xF1cabrahm\u0101tmatattvata\u1E25 \u096525\u0965</p><p>\u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u043F\u0440\u043E\u0438\u0437\u043D\u043E\u0441\u0438\u0442\u044C \u043F\u0430\u043D\u0447\u0430\u043A\u0448\u0430\u0440\u0430 [\u043C\u0430\u043D\u0442\u0440\u0443] \u043E\u0442 \u041D\u0410 \u0434\u043E \u0419\u0410. \u0421\u043B\u0435\u0434\u0443\u0435\u0442 \u0437\u043D\u0430\u0442\u044C \u0432\u0441\u0451 \u043A\u0430\u043A \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u044B\u0439 \u0410\u0442\u043C\u0430\u043D, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u0441\u0430\u043C\u0430 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u041F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E\u0433\u043E \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430.</p></div><div class="stanza"><a href="#s26" id="s26" class="num">26</a><p class="sans">\u092A\u091E\u094D\u091A\u092C\u094D\u0930\u0939\u094D\u092E\u093E\u0924\u094D\u092E\u093F\u0915\u0940\u0902 \u0935\u093F\u0926\u094D\u092F\u093E\u0902 \u092F\u094B\u093D\u0927\u0940\u0924\u0947 \u092D\u0915\u094D\u0924\u093F\u092D\u093E\u0935\u093F\u0924\u0903 \u0964<br> \u0938 \u092A\u091E\u094D\u091A\u093E\u0924\u094D\u092E\u0915\u0924\u093E\u092E\u0947\u0924\u094D\u092F \u092D\u093E\u0938\u0924\u0947 \u092A\u091E\u094D\u091A\u0927\u093E \u0938\u094D\u0935\u092F\u092E\u094D \u0965\u0968\u096C\u0965</p><p class="trans">pa\xF1cabrahm\u0101tmik\u012B\u1E41 vidy\u0101\u1E41 yo&#39;dh\u012Bte bhaktibh\u0101vita\u1E25 \u0964<br> sa pa\xF1c\u0101tmakat\u0101metya bh\u0101sate pa\xF1cadh\u0101 svayam \u096526\u0965</p><p>\u041A\u0442\u043E \u0441 \u0447\u0443\u0432\u0441\u0442\u0432\u043E\u043C \u043F\u0440\u0435\u0434\u0430\u043D\u043D\u043E\u0441\u0442\u0438 \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u0435\u0442 \u0432\u0438\u0434\u044C\u044E, \u0441\u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0449\u0443\u044E \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u044C \u043F\u044F\u0442\u0438 \u0411\u0440\u0430\u0445\u043C, \u0442\u043E\u0442 \u0434\u043E\u0441\u0442\u0438\u0433\u0430\u0435\u0442 \u044D\u0442\u043E\u0439 \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E\u0439 \u0421\u0443\u0449\u043D\u043E\u0441\u0442\u0438 (\u043A\u043E\u0442\u043E\u0440\u0430\u044F) \u0441\u0438\u044F\u0435\u0442 \u0432 \u043D\u0435\u043C \u043F\u044F\u0442\u0435\u0440\u0438\u0447\u043D\u043E.</p></div><div class="stanza"><a href="#s27" id="s27" class="num">27</a><p class="sans">\u090F\u0935\u092E\u0941\u0915\u094D\u0924\u094D\u0935\u093E \u092E\u0939\u093E\u0926\u0947\u0935\u094B \u0917\u093E\u0932\u0935\u0938\u094D\u092F \u092E\u0939\u093E\u0924\u094D\u092E\u0928\u0903 \u0964<br> \u0915\u0943\u092A\u093E\u0902 \u091A\u0915\u093E\u0930 \u0924\u0924\u094D\u0930\u0948\u0935 \u0938\u094D\u0935\u093E\u0928\u094D\u0924\u0930\u094D\u0927\u093F\u092E\u0917\u092E\u0924\u094D\u0938\u094D\u0935\u092F\u092E\u094D \u0965\u0968\u096D\u0965</p><p class="trans">evamuktv\u0101 mah\u0101devo g\u0101lavasya mah\u0101tmana\u1E25 \u0964<br> k\u1E5Bp\u0101\u1E41 cak\u0101ra tatraiva sv\u0101ntardhimagamatsvayam \u096527\u0965</p><p>\u0422\u0430\u043A \u043F\u043E\u0432\u0435\u0434\u0430\u043B \u041C\u0430\u0445\u0430\u0434\u0435\u0432\u0430 \u0413\u0430\u043B\u0430\u0432\u0435, \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u0434\u0443\u0448\u0435. \u041E\u043A\u0430\u0437\u0430\u0432 \u043C\u0438\u043B\u043E\u0441\u0442\u044C, \u041E\u043D \u0432\u0435\u0440\u043D\u0443\u043B\u0441\u044F \u0432 \u0441\u0432\u043E\u044E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044E\u044E \u043E\u0431\u0438\u0442\u0435\u043B\u044C.</p></div><div class="stanza"><a href="#s28" id="s28" class="num">28</a><p class="sans">\u092F\u0938\u094D\u092F \u0936\u094D\u0930\u0935\u0923\u092E\u093E\u0924\u094D\u0930\u0947\u0923\u093E\u0936\u094D\u0930\u0941\u0924\u092E\u0947\u0935 \u0936\u094D\u0930\u0941\u0924\u0902 \u092D\u0935\u0947\u0924\u094D \u0964<br> \u0905\u092E\u0924\u0902 \u091A \u092E\u0924\u0902 \u091C\u094D\u091E\u093E\u0924\u092E\u0935\u093F\u091C\u094D\u091E\u093E\u0924\u0902 \u091A \u0936\u093E\u0915\u0932 \u0965\u0968\u096E\u0965</p><p class="trans">yasya \u015Brava\u1E47am\u0101tre\u1E47\u0101\u015Brutameva \u015Bruta\u1E41 bhavet \u0964<br> amata\u1E41 ca mata\u1E41 j\xF1\u0101tamavij\xF1\u0101ta\u1E41 ca \u015B\u0101kala \u096528\u0965</p><p>\u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0441\u043B\u0443\u0448\u0430\u043D\u0438\u044E [\u043E\u0431 \u044D\u0442\u043E\u043C] \u043D\u0435 \u0443\u0447\u0451\u043D\u044B\u0439 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u0443\u0447\u0451\u043D\u044B\u043C, \u043D\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u0439 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u043E\u043D\u0438\u043C\u0430\u044E\u0449\u0438\u043C, \u043D\u0435 \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0438\u0439 \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u043E\u0437\u043D\u0430\u0432\u0448\u0438\u043C, \u043E \u0428\u0430\u043A\u0430\u043B\u0430.</p></div><div class="stanza"><a href="#s29" id="s29" class="num">29</a><p class="sans">\u090F\u0915\u0947\u0928\u0948\u0935 \u0924\u0941 \u092A\u093F\u0923\u094D\u0921\u0947\u0928 \u092E\u0943\u0924\u094D\u0924\u093F\u0915\u093E\u092F\u093E\u0936\u094D\u091A \u0917\u094C\u0924\u092E \u0964<br> \u0935\u093F\u091C\u094D\u091E\u093E\u0924\u0902 \u092E\u0943\u0923\u094D\u092E\u092F\u0902 \u0938\u0930\u094D\u0935\u0902 \u092E\u0943\u0926\u092D\u093F\u0928\u094D\u0928\u0902 \u0939\u093F \u0915\u093E\u092F\u0915\u092E\u094D \u0965\u0968\u096F\u0965</p><p class="trans">ekenaiva tu pi\u1E47\u1E0Dena m\u1E5Bttik\u0101y\u0101\u015Bca gautama \u0964<br> vij\xF1\u0101ta\u1E41 m\u1E5B\u1E47maya\u1E41 sarva\u1E41 m\u1E5Bdabhinna\u1E41 hi k\u0101yakam \u096529\u0965</p><p>\u0411\u0443\u0434\u0443\u0447\u0438 \u0435\u0434\u0438\u043D\u044B\u043C, \u043A\u0443\u0441\u043E\u043A \u0433\u043B\u0438\u043D\u044B \u0442\u0435\u043B\u0435\u0441\u043D\u043E \u043E\u0442\u043B\u0438\u0447\u0430\u0435\u0442\u0441\u044F \u043E\u0442 \u0432\u0441\u0435\u0439 \u0433\u043B\u0438\u043D\u044F\u043D\u043E\u0439 \u043F\u043E\u0441\u0443\u0434\u044B \u0438\u0437 \u043D\u0435\u0433\u043E \u0438\u0437\u0433\u043E\u0442\u043E\u0432\u043B\u0435\u043D\u043D\u043E\u0439.</p></div><div class="stanza"><a href="#s30" id="s30" class="num">30</a><p class="sans">\u090F\u0915\u0947\u0928 \u0932\u094B\u0939\u092E\u0923\u093F\u0928\u093E \u0938\u0930\u094D\u0935\u0902 \u0932\u094B\u0939\u092E\u092F\u0902 \u092F\u0925\u093E \u0964<br> \u0935\u093F\u091C\u094D\u091E\u093E\u0924\u0902 \u0938\u094D\u092F\u093E\u0926\u0925\u0948\u0915\u0947\u0928 \u0928\u0916\u093E\u0928\u093E\u0902 \u0915\u0943\u0928\u094D\u0924\u0928\u0947\u0928 \u091A \u0965\u0969\u0966\u0965</p><p class="trans">ekena lohama\u1E47in\u0101 sarva\u1E41 lohamaya\u1E41 yath\u0101 \u0964<br> vij\xF1\u0101ta\u1E41 sy\u0101dathaikena nakh\u0101n\u0101\u1E41 k\u1E5Bntanena ca \u096530\u0965</p><p>\u041E\u0434\u0438\u043D \u043A\u0443\u0441\u043E\u043A \u043C\u0435\u0442\u0430\u043B\u043B\u0430 \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C [\u043F\u043E\u0445\u043E\u0436 \u043D\u0430 \u0434\u0440\u0443\u0433\u0438\u0435] \u0438 \u0435\u0434\u0438\u043D \u0441 \u0434\u0440\u0443\u0433\u0438\u043C\u0438 \u043C\u0435\u0442\u0430\u043B\u043B\u0438\u0447\u0435\u0441\u043A\u0438\u043C\u0438 \u0438\u0437\u0434\u0435\u043B\u0438\u044F\u043C\u0438, \u043D\u043E \u043F\u0440\u043E\u0432\u0435\u0440\u044F\u0435\u0442\u0441\u044F \u0446\u0430\u0440\u0430\u043F\u0430\u043D\u0438\u0435\u043C \u043D\u043E\u0433\u0442\u0451\u043C.</p></div><div class="stanza"><a href="#s31" id="s31" class="num">31</a><p class="sans">\u0938\u0930\u094D\u0935\u0902 \u0915\u093E\u0930\u094D\u0937\u094D\u0923\u093E\u092F\u0938\u0902 \u091C\u094D\u091E\u093E\u0924\u0902 \u0924\u0926\u092D\u093F\u0928\u094D\u0928\u0902 \u0938\u094D\u0935\u092D\u093E\u0935\u0924\u0903 \u0964<br> \u0915\u093E\u0930\u0923\u093E\u092D\u093F\u0928\u094D\u0928\u0930\u0942\u092A\u0947\u0923 \u0915\u093E\u0930\u094D\u092F\u0902 \u0915\u093E\u0930\u0923\u092E\u0947\u0935 \u0939\u093F \u0965\u0969\u0967\u0965</p><p class="trans">sarva\u1E41 k\u0101r\u1E63\u1E47\u0101yasa\u1E41 j\xF1\u0101ta\u1E41 tadabhinna\u1E41 svabh\u0101vata\u1E25 \u0964<br> k\u0101ra\u1E47\u0101bhinnar\u016Bpe\u1E47a k\u0101rya\u1E41 k\u0101ra\u1E47ameva hi \u096531\u0965</p><p>\u0422\u0430\u043A \u0432\u0441\u0435 \u043F\u043E\u0437\u043D\u0430\u0451\u0442\u0441\u044F \u043D\u0435\u043E\u0442\u043B\u0438\u0447\u043D\u044B\u043C \u043E\u0442 \u0441\u0432\u043E\u0435\u0439 \u043F\u043E\u0431\u0443\u0434\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0439 \u043F\u0440\u0438\u0447\u0438\u043D\u044B, \u0430 \u0441\u0430\u043C\u0430 \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u043D\u0435\u043E\u0442\u0434\u0435\u043B\u0438\u043C\u0430 \u043E\u0442 \u0441\u043B\u0435\u0434\u0441\u0442\u0432\u0438\u044F \u0438 \u0438\u043D\u0441\u0442\u0440\u0443\u043C\u0435\u043D\u0442\u0430 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F.</p></div><div class="stanza"><a href="#s32" id="s32" class="num">32</a><p class="sans">\u0924\u0926\u094D\u0930\u0942\u092A\u0947\u0923 \u0938\u0926\u093E \u0938\u0924\u094D\u092F\u0902 \u092D\u0947\u0926\u0947\u0928\u094B\u0915\u094D\u0924\u093F\u0930\u094D\u092E\u0943\u0937\u093E \u0916\u0932\u0941 \u0964<br> \u0924\u091A\u094D\u091A \u0915\u093E\u0930\u0923\u092E\u0947\u0915\u0902 \u0939\u093F \u0928 \u092D\u093F\u0928\u094D\u0928\u0902 \u0928\u094B\u092D\u092F\u093E\u0924\u094D\u092E\u0915\u092E\u094D \u0965\u0969\u0968\u0965</p><p class="trans">tadr\u016Bpe\u1E47a sad\u0101 satya\u1E41 bhedenoktirm\u1E5B\u1E63\u0101 khalu \u0964<br> tacca k\u0101ra\u1E47ameka\u1E41 hi na bhinna\u1E41 nobhay\u0101tmakam \u096532\u0965</p><p>\u0422\u0430\u043A \u0438 \u0418\u0441\u0442\u0438\u043D\u0430 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439, \u043D\u043E \u044D\u0442\u043E \u2013 \u043C\u0438\u0440\u0430\u0436. \u041F\u0440\u0438\u0447\u0438\u043D\u0430 \u043E\u0434\u043D\u0430, \u043D\u0435\u0442 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u0438, \u043D\u0435\u0442 \u043E\u0441\u043D\u043E\u0432\u0430\u043D\u0438\u044F \u0434\u043B\u044F \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s33" id="s33" class="num">33</a><p class="sans">\u092D\u0947\u0926\u0903 \u0938\u0930\u094D\u0935\u0924\u094D\u0930 \u092E\u093F\u0925\u094D\u092F\u0948\u0935 \u0927\u0930\u094D\u092E\u093E\u0926\u0947\u0930\u0928\u093F\u0930\u0942\u092A\u0923\u093E\u0924\u094D \u0964<br> \u0905\u0924\u0936\u094D\u091A \u0915\u093E\u0930\u0923\u0902 \u0928\u093F\u0924\u094D\u092F\u092E\u0947\u0915\u092E\u0947\u0935\u093E\u0926\u094D\u0935\u092F\u0902 \u0916\u0932\u0941 \u0965\u0969\u0969\u0965</p><p class="trans">bheda\u1E25 sarvatra mithyaiva dharm\u0101deranir\u016Bpa\u1E47\u0101t \u0964<br> ata\u015Bca k\u0101ra\u1E47a\u1E41 nityamekamev\u0101dvaya\u1E41 khalu \u096533\u0965</p><p>\u0420\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 \u0432\u0441\u0435\u0433\u0434\u0430 \u043B\u043E\u0436\u043D\u043E, \u043D\u0435\u043E\u043F\u0438\u0441\u0443\u0435\u043C\u044B \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0430 (\u0432\u044B\u0441\u0448\u0435\u0439 \u0420\u0435\u0430\u043B\u044C\u043D\u043E\u0441\u0442\u0438). \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u041F\u0440\u0438\u0447\u0438\u043D\u0430 \u0432\u0441\u0435\u0433\u043E \u0432\u0435\u0447\u043D\u043E \u0435\u0434\u0438\u043D\u0430, \u0431\u0435\u0437 \u0432\u0442\u043E\u0440\u043E\u0433\u043E.</p></div><div class="stanza"><a href="#s34" id="s34" class="num">34</a><p class="sans">\u0905\u0924\u094D\u0930 \u0915\u093E\u0930\u0923\u092E\u0926\u094D\u0935\u0948\u0924\u0902 \u0936\u0941\u0926\u094D\u0927\u091A\u0948\u0924\u0928\u094D\u092F\u092E\u0947\u0935 \u0939\u093F \u0964<br> \u0905\u0938\u094D\u092E\u093F\u0928\u094D\u092C\u094D\u0930\u0939\u094D\u092E\u092A\u0941\u0930\u0947 \u0935\u0947\u0936\u094D\u092E \u0926\u0939\u0930\u0902 \u092F\u0926\u093F\u0926\u0902 \u092E\u0941\u0928\u0947 \u0965\u0969\u096A\u0965</p><p class="trans">atra k\u0101ra\u1E47amadvaita\u1E41 \u015Buddhacaitanyameva hi \u0964<br> asminbrahmapure ve\u015Bma dahara\u1E41 yadida\u1E41 mune \u096534\u0965</p><p>\u041D\u0435\u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u0438\u0447\u0438\u043D\u0430 \u0435\u0441\u0442\u044C \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435. \u0412 \u044D\u0442\u043E\u043C \u0433\u043E\u0440\u043E\u0434\u0435 \u0411\u0440\u0430\u0445\u043C\u0430\u043D\u0430 \u0435\u0441\u0442\u044C \u043C\u0430\u043B\u044B\u0439 \u0434\u043E\u043C, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0435\u0441\u0442\u044C \u044D\u0442\u0430 (\u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F) \u043E, \u041C\u0443\u0434\u0440\u0435\u0446!</p></div><div class="stanza"><a href="#s35" id="s35" class="num">35</a><p class="sans">\u092A\u0941\u0923\u094D\u0921\u0930\u0940\u0915\u0902 \u0924\u0941 \u0924\u0928\u094D\u092E\u0927\u094D\u092F\u0947 \u0906\u0915\u093E\u0936\u094B \u0926\u0939\u0930\u094B\u093D\u0938\u094D\u0924\u093F \u0924\u0924\u094D \u0964<br> \u0938 \u0936\u093F\u0935\u0903 \u0938\u091A\u094D\u091A\u093F\u0926\u093E\u0928\u0928\u094D\u0926\u0903 \u0938\u094B\u093D\u0928\u094D\u0935\u0947\u0937\u094D\u091F\u0935\u094D\u092F\u094B \u092E\u0941\u092E\u0941\u0915\u094D\u0936\u093F\u092D\u093F\u0903 \u0965\u0969\u096B\u0965</p><p class="trans">pu\u1E47\u1E0Dar\u012Bka\u1E41 tu tanmadhye \u0101k\u0101\u015Bo daharo&#39;sti tat \u0964<br> sa \u015Biva\u1E25 saccid\u0101nanda\u1E25 so&#39;nve\u1E63\u1E6Davyo mumuk\u015Bibhi\u1E25 \u096535\u0965</p><p>\u0412 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u0435\u0433\u043E \u2013 \u043B\u043E\u0442\u043E\u0441, \u0432 \u043D\u0435\u043C \u043D\u0430\u0445\u043E\u0434\u0438\u0442\u0441\u044F \u043C\u0430\u043B\u043E\u0435 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u043E. \u042D\u0442\u043E \u2013 \u0428\u0438\u0432\u0430, \u0411\u044B\u0442\u0438\u0435, \u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435, \u0411\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u043A \u041A\u043E\u0442\u043E\u0440\u043E\u043C\u0443 \u0443\u0441\u0442\u0440\u0435\u043C\u043B\u044F\u044E\u0442\u0441\u044F \u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F.</p></div><div class="stanza"><a href="#s36" id="s36" class="num">36</a><p class="sans">\u0905\u092F\u0902 \u0939\u0943\u0926\u093F \u0938\u094D\u0925\u093F\u0924\u0903 \u0938\u093E\u0915\u094D\u0936\u0940 \u0938\u0930\u094D\u0935\u0947\u0937\u093E\u092E\u0935\u093F\u0936\u0947\u0937\u0924\u0903 \u0964<br> \u0924\u0947\u0928\u093E\u092F\u0902 \u0939\u0943\u0926\u092F\u0902 \u092A\u094D\u0930\u094B\u0915\u094D\u0924\u0903 \u0936\u093F\u0935\u0903 \u0938\u0902\u0938\u093E\u0930\u092E\u094B\u091A\u0915\u0903 \u0965\u0969\u096C\u0965</p><p class="trans">aya\u1E41 h\u1E5Bdi sthita\u1E25 s\u0101k\u015B\u012B sarve\u1E63\u0101mavi\u015Be\u1E63ata\u1E25 \u0964<br> ten\u0101ya\u1E41 h\u1E5Bdaya\u1E41 prokta\u1E25 \u015Biva\u1E25 sa\u1E41s\u0101ramocaka\u1E25 \u096536\u0965</p><p>\u0412 \u044D\u0442\u043E\u043C \u0421\u0435\u0440\u0434\u0446\u0435 \u043F\u0440\u0435\u0431\u044B\u0432\u0430\u0435\u0442 \u0421\u0432\u0438\u0434\u0435\u0442\u0435\u043B\u044C \u0432\u0441\u0435\u0433\u043E \u0431\u0435\u0437 \u043E\u0441\u0442\u0430\u0442\u043A\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044D\u0442\u043E \u0421\u0435\u0440\u0434\u0446\u0435 \u0438\u043C\u0435\u043D\u0443\u0435\u0442\u0441\u044F \u0428\u0438\u0432\u043E\u0439, \u0421\u043F\u0430\u0441\u0430\u044E\u0449\u0438\u043C \u0438\u0437 \u0441\u0430\u043C\u0441\u0430\u0440\u044B.</p></div><p class="sans">\u0965\u0907\u0924\u094D\u092F\u0941\u092A\u0928\u093F\u0937\u0924\u094D \u0965</p><p class="trans">\u0965ityupani\u1E63at \u0965</p><p>\u0422\u0430\u043A\u043E\u0432\u0430 \u0443\u043F\u0430\u043D\u0438\u0448\u0430\u0434\u0430.</p>',40),n=[i];function v(d,m,c,h,l,b){return r(),s("div",null,n)}var y=a(p,[["render",v]]);export{k as __pageData,y as default};
